import json
import re
from dataclasses import dataclass
from pathlib import Path
from typing import Dict, List, Tuple

import torch
from peft import PeftModel
from transformers import AutoProcessor, Qwen2_5_VLForConditionalGeneration

GRID_SIZE = 1000.0
DEFAULT_MIN_PIXELS = 256 * 28 * 28
DEFAULT_MAX_PIXELS = 512 * 28 * 28
BASE_MODEL_DIR = Path("/data/base_model/Qwen2.5-VL-3B-Instruct")


@dataclass
class ParsedPrediction:
    kind: str
    values: List[float]
    raw_text: str = ""


def _has_model_weights(path: Path) -> bool:
    if not path.exists() or not path.is_dir():
        return False
    weight_names = [
        "model.safetensors",
        "model.safetensors.index.json",
        "pytorch_model.bin",
        "pytorch_model.bin.index.json",
    ]
    return any((path / name).exists() for name in weight_names)


def _existing(path: Path) -> bool:
    try:
        return path.exists()
    except Exception:
        return False


def _candidate_base_dirs(ckpt_dir: Path) -> List[Path]:
    cwd = Path.cwd()
    cands: List[Path] = []

    local_names = [
        ckpt_dir / "base_model",
        ckpt_dir.parent / "base_model",
        ckpt_dir.parent / "baseline" / "base_model",
        ckpt_dir.parent.parent / "baseline" / "base_model",
        Path("checkpoints/baseline/base_model"),
        cwd / "checkpoints" / "baseline" / "base_model",
        cwd / "baseline" / "base_model",
        Path("/workspace/checkpoints/baseline/base_model"),
        Path("/workspace/baseline/base_model"),
    ]
    cands.extend(local_names)

    meta_path = ckpt_dir / "meta.json"
    if meta_path.exists():
        try:
            meta = json.loads(meta_path.read_text())
            for key in ["base_model_dir", "base_model", "base_dir"]:
                base = meta.get(key)
                if not base:
                    continue
                base_path = Path(base)
                if base_path.is_absolute():
                    cands.append(base_path)
                    if base_path.name != "base_model":
                        cands.append(base_path.parent / "base_model")
                else:
                    cands.append(ckpt_dir / base_path)
                    cands.append(ckpt_dir.parent / base_path)
                    cands.append(cwd / base_path)
        except Exception:
            pass

    cands.append(BASE_MODEL_DIR)

    uniq: List[Path] = []
    seen = set()
    for p in cands:
        try:
            key = str(p.resolve()) if _existing(p) else str(p)
        except Exception:
            key = str(p)
        if key not in seen:
            seen.add(key)
            uniq.append(p)
    return uniq


def resolve_base_model_dir(checkpoint: str) -> str:
    ckpt_dir = Path(checkpoint)
    if ckpt_dir.is_file():
        ckpt_dir = ckpt_dir.parent
    for cand in _candidate_base_dirs(ckpt_dir):
        if _has_model_weights(cand):
            return str(cand)
    tried = [str(p) for p in _candidate_base_dirs(ckpt_dir)]
    raise FileNotFoundError(f"Could not find packaged base model for checkpoint {checkpoint}; tried: {tried}")


def load_processor(checkpoint_or_model_dir: str, min_pixels: int = DEFAULT_MIN_PIXELS, max_pixels: int = DEFAULT_MAX_PIXELS):
    p = Path(checkpoint_or_model_dir)
    candidates = []
    if (p / "processor").exists():
        candidates.append(p / "processor")
    candidates.append(p)
    try:
        base_dir = Path(resolve_base_model_dir(str(p)))
        if (base_dir / "processor").exists():
            candidates.append(base_dir / "processor")
        candidates.append(base_dir)
    except Exception:
        pass

    last_err = None
    for use_dir in candidates:
        try:
            return AutoProcessor.from_pretrained(
                str(use_dir),
                local_files_only=True,
                min_pixels=min_pixels,
                max_pixels=max_pixels,
                trust_remote_code=False,
            )
        except Exception as e:
            last_err = e
    raise last_err


def row_to_point(row: Dict) -> Tuple[float, float]:
    if row.get("target_point") is not None:
        return float(row["target_point"][0]), float(row["target_point"][1])
    x1, y1, x2, y2 = row["target_bbox"]
    return float((x1 + x2) / 2.0), float((y1 + y2) / 2.0)


def target_to_text(row: Dict, grid_size: int = int(GRID_SIZE)) -> str:
    w = max(float(row["image_width"]), 1.0)
    h = max(float(row["image_height"]), 1.0)
    x, y = row_to_point(row)
    gx = int(round(x / w * grid_size))
    gy = int(round(y / h * grid_size))
    gx = max(0, min(grid_size, gx))
    gy = max(0, min(grid_size, gy))
    return f"<point>{gx} {gy}</point>"


def build_messages(row: Dict):
    instruction = row["instruction"].strip()
    return [
        {
            "role": "system",
            "content": [
                {
                    "type": "text",
                    "text": "You are a GUI grounding assistant. Output only one point in the exact format <point>x y</point> using a 0-1000 coordinate grid.",
                }
            ],
        },
        {
            "role": "user",
            "content": [
                {"type": "image", "image": row["image"]},
                {"type": "text", "text": instruction},
            ],
        },
    ]


def _extract_numbers(text: str) -> List[float]:
    return [float(x) for x in re.findall(r"-?\d+(?:\.\d+)?", text)]


def clip_point(x: float, y: float, w: float, h: float) -> List[float]:
    return [float(min(max(x, 0.0), w)), float(min(max(y, 0.0), h))]


def clip_bbox(x1: float, y1: float, x2: float, y2: float, w: float, h: float) -> List[float]:
    x1 = min(max(x1, 0.0), w)
    x2 = min(max(x2, 0.0), w)
    y1 = min(max(y1, 0.0), h)
    y2 = min(max(y2, 0.0), h)
    if x2 < x1:
        x1, x2 = x2, x1
    if y2 < y1:
        y1, y2 = y2, y1
    return [float(x1), float(y1), float(x2), float(y2)]


def _grid_to_abs_xy(gx: float, gy: float, image_width: float, image_height: float) -> List[float]:
    x = gx / GRID_SIZE * float(image_width)
    y = gy / GRID_SIZE * float(image_height)
    return clip_point(x, y, float(image_width), float(image_height))


def _grid_to_abs_bbox(vals: List[float], image_width: float, image_height: float) -> List[float]:
    x1 = vals[0] / GRID_SIZE * float(image_width)
    y1 = vals[1] / GRID_SIZE * float(image_height)
    x2 = vals[2] / GRID_SIZE * float(image_width)
    y2 = vals[3] / GRID_SIZE * float(image_height)
    return clip_bbox(x1, y1, x2, y2, float(image_width), float(image_height))


def parse_prediction_text(text: str, image_width: float, image_height: float) -> ParsedPrediction:
    raw = text.strip()

    m = re.search(r"<point>\s*([\d.]+)[,\s]+([\d.]+)\s*</point>", raw, flags=re.I)
    if m:
        pt = _grid_to_abs_xy(float(m.group(1)), float(m.group(2)), image_width, image_height)
        return ParsedPrediction("point", pt, raw)

    m = re.search(r"<point[^>]*x1\s*=\s*['\"]?([\d.]+)['\"]?[^>]*y1\s*=\s*['\"]?([\d.]+)['\"]?[^>]*>", raw, flags=re.I)
    if m:
        pt = _grid_to_abs_xy(float(m.group(1)), float(m.group(2)), image_width, image_height)
        return ParsedPrediction("point", pt, raw)

    m = re.search(r"<box>\s*([\d.]+)[,\s]+([\d.]+)[,\s]+([\d.]+)[,\s]+([\d.]+)\s*</box>", raw, flags=re.I)
    if m:
        box = _grid_to_abs_bbox([float(m.group(i)) for i in range(1, 5)], image_width, image_height)
        return ParsedPrediction("bbox", box, raw)

    m = re.search(r"<bbox>\s*\(?\s*([\d.]+)\s*,\s*([\d.]+)\s*\)?\s*,?\s*\(?\s*([\d.]+)\s*,\s*([\d.]+)\s*\)?\s*</bbox>", raw, flags=re.I)
    if m:
        box = _grid_to_abs_bbox([float(m.group(i)) for i in range(1, 5)], image_width, image_height)
        return ParsedPrediction("bbox", box, raw)

    nums = _extract_numbers(raw)
    if len(nums) >= 2:
        pt = _grid_to_abs_xy(nums[0], nums[1], image_width, image_height)
        return ParsedPrediction("point", pt, raw)

    cx = float(image_width) / 2.0
    cy = float(image_height) / 2.0
    return ParsedPrediction("point", [cx, cy], raw)


def load_model_for_inference(checkpoint: str, min_pixels: int = DEFAULT_MIN_PIXELS, max_pixels: int = DEFAULT_MAX_PIXELS):
    ckpt_dir = Path(checkpoint)
    base_dir = resolve_base_model_dir(str(ckpt_dir))
    processor = load_processor(str(ckpt_dir), min_pixels=min_pixels, max_pixels=max_pixels)

    model = Qwen2_5_VLForConditionalGeneration.from_pretrained(
        base_dir,
        torch_dtype=torch.float16,
        local_files_only=True,
        trust_remote_code=False,
        device_map="auto",
    )
    if (ckpt_dir / "adapter_config.json").exists():
        model = PeftModel.from_pretrained(model, str(ckpt_dir), local_files_only=True)
    model.eval()
    return model, processor


def generate_prediction(model, processor, image, instruction: str, image_width: float, image_height: float) -> Dict:
    row = {
        "instruction": instruction,
        "image": image,
        "image_width": image_width,
        "image_height": image_height,
    }
    messages = build_messages(row)
    text = processor.apply_chat_template(messages, tokenize=False, add_generation_prompt=True)
    device = next(model.parameters()).device
    inputs = processor(text=[text], images=[image], padding=True, return_tensors="pt")
    inputs = {k: (v.to(device) if hasattr(v, "to") else v) for k, v in inputs.items()}
    with torch.no_grad():
        out_ids = model.generate(
            **inputs,
            max_new_tokens=16,
            do_sample=False,
            use_cache=True,
        )
    gen_ids = out_ids[:, inputs["input_ids"].shape[1]:]
    raw_text = processor.batch_decode(gen_ids, skip_special_tokens=True, clean_up_tokenization_spaces=False)[0]
    parsed = parse_prediction_text(raw_text, image_width, image_height)
    if parsed.kind == "bbox":
        return {"bbox": parsed.values, "raw_text": parsed.raw_text}
    return {"point": parsed.values, "raw_text": parsed.raw_text}
